from collections import deque

class Solution:
    def minimumOperationsToMakeEqual(self, x: int, y: int) -> int:
        if x == y:
            return 0
        q = deque([(x, 0)])
        seen = {x}
        while q:
            val, steps = q.popleft()
            if val == y:
                return steps
            for nxt in (val - 1, val + 1):
                if nxt == y:
                    return steps + 1
                if 1 <= nxt <= 10000 and nxt not in seen:
                    seen.add(nxt)
                    q.append((nxt, steps + 1))
            if val % 11 == 0:
                nxt = val // 11
                if nxt == y:
                    return steps + 1
                if nxt not in seen:
                    seen.add(nxt)
                    q.append((nxt, steps + 1))
            if val % 5 == 0:
                nxt = val // 5
                if nxt == y:
                    return steps + 1
                if nxt not in seen:
                    seen.add(nxt)
                    q.append((nxt, steps + 1))
        return -1
```
